package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // Override read(char[], int, int) to call super.read from BufferedReader
            @Override
            public int read(char[] buf, int offset, int length) throws IOException {
                return super.read(buf, offset, length);
            }
        };
    }

    // Helper to set private field lastChar
    private void setLastChar(int value) throws Exception {
        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        lastCharField.setInt(extendedBufferedReader, value);
    }

    // Helper to get private field lastChar
    private int getLastChar() throws Exception {
        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        return lastCharField.getInt(extendedBufferedReader);
    }

    // Helper to get private field lineCounter
    private int getLineCounter() throws Exception {
        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        return lineCounterField.getInt(extendedBufferedReader);
    }

    // Since the focal method calls super.read(buf, offset, length),
    // we need to spy on extendedBufferedReader to mock super.read behavior.
    // We create a subclass to override super.read calls.

    @Test
    void testReadLengthZeroReturnsZero() throws IOException {
        char[] buf = new char[10];
        int result = extendedBufferedReader.read(buf, 0, 0);
        assertEquals(0, result);
    }

    @Test
    void testReadReturnsMinusOneSetsLastCharToEndOfStream() throws Exception {
        char[] buf = new char[10];
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(-1).when(spyReader).read(Mockito.any(char[].class), anyInt(), anyInt());

        int result = spyReader.read(buf, 0, 5);

        assertEquals(-1, result);

        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        int lastCharValue = lastCharField.getInt(spyReader);
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastCharValue);
    }

    @Test
    void testReadWithNewlineNotPrecededByCarriageReturnIncrementsLineCounter() throws Exception {
        // buf contains chars: a \n b
        char[] buf = new char[]{'a', '\n', 'b'};
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        // simulate super.read returns 3 (fills buf from offset 0 length 3)
        doReturn(3).when(spyReader).read(Mockito.any(char[].class), eq(0), eq(3));

        // Set lastChar to something not \r
        setLastChar(ExtendedBufferedReader.UNDEFINED);

        int len = spyReader.read(buf, 0, 3);

        assertEquals(3, len);

        // lineCounter should increment once for \n (buf[1]) not preceded by \r (buf[0] is 'a')
        int lineCounter = getLineCounter(spyReader);
        assertEquals(1, lineCounter);

        // lastChar should be buf[offset + len - 1] = buf[2] = 'b'
        int lastChar = getLastChar(spyReader);
        assertEquals('b', lastChar);
    }

    @Test
    void testReadWithNewlinePrecededByCarriageReturnDoesNotIncrementLineCounter() throws Exception {
        // buf contains chars: \r \n
        char[] buf = new char[]{'\r', '\n'};
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(2).when(spyReader).read(Mockito.any(char[].class), eq(0), eq(2));

        setLastChar(ExtendedBufferedReader.UNDEFINED);

        int len = spyReader.read(buf, 0, 2);

        assertEquals(2, len);
        int lineCounter = getLineCounter(spyReader);
        // \r increments lineCounter by 1, \n preceded by \r does not increment
        assertEquals(1, lineCounter);

        int lastChar = getLastChar(spyReader);
        assertEquals('\n', lastChar);
    }

    @Test
    void testReadWithCarriageReturnIncrementsLineCounter() throws Exception {
        // buf contains chars: a \r b
        char[] buf = new char[]{'a', '\r', 'b'};
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(3).when(spyReader).read(Mockito.any(char[].class), eq(0), eq(3));

        setLastChar(ExtendedBufferedReader.UNDEFINED);

        int len = spyReader.read(buf, 0, 3);

        assertEquals(3, len);

        // lineCounter increments once for \r at buf[1]
        int lineCounter = getLineCounter(spyReader);
        assertEquals(1, lineCounter);

        int lastChar = getLastChar(spyReader);
        assertEquals('b', lastChar);
    }

    @Test
    void testReadWithOffsetNonZero() throws Exception {
        // buf contains: x x \n
        char[] buf = new char[]{'x', 'x', '\n', 'a', 'b'};
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn(3).when(spyReader).read(Mockito.any(char[].class), eq(1), eq(3));

        setLastChar(ExtendedBufferedReader.UNDEFINED);

        int len = spyReader.read(buf, 1, 3);

        assertEquals(3, len);

        // The read chars are buf[1], buf[2], buf[3] = 'x', '\n', 'a'
        // '\n' at index 2 is preceded by buf[1] = 'x' != '\r' so lineCounter increments
        int lineCounter = getLineCounter(spyReader);
        assertEquals(1, lineCounter);

        int lastChar = getLastChar(spyReader);
        assertEquals('a', lastChar);
    }

    // Helpers to get private fields from spyReader
    private int getLineCounter(ExtendedBufferedReader spyReader) throws Exception {
        Field lineCounterField = ExtendedBufferedReader.class.getDeclaredField("lineCounter");
        lineCounterField.setAccessible(true);
        return lineCounterField.getInt(spyReader);
    }

    private int getLastChar(ExtendedBufferedReader spyReader) throws Exception {
        Field lastCharField = ExtendedBufferedReader.class.getDeclaredField("lastChar");
        lastCharField.setAccessible(true);
        return lastCharField.getInt(spyReader);
    }
}
